function solve(nums1, nums0) {
    const MOD = 1000000007n;

    /**
     * Modular exponentiation: (base^exp) % mod
     * Uses BigInt for safety.
     */
    const power = (base, exp, mod) => {
        let res = 1n;
        base = base % mod;
        let e = BigInt(exp);
        while (e > 0n) {
            if (e % 2n === 1n) {
                res = (res * base) % mod;
            }
            base = (base * base) % mod;
            e /= 2n;
        }
        return res;
    };

    const N = nums1.length;
    const fragments = [];

    // 1. Store fragment properties
    for (let i = 0; i < N; i++) {
        const n1 = nums1[i];
        const n0 = nums0[i];
        const length = n1 + n0;

        // Store (n1, n0, length)
        fragments.push({ n1, n0, length });
    }

    // 2. Custom sorting based on greedy rule: AB > BA
    // S_i precedes S_j if (n1_i > n1_j) OR (n1_i == n1_j AND n0_i < n0_j)
    fragments.sort((a, b) => {
        // Primary sort criterion: More ones first (descending n1)
        if (a.n1 !== b.n1) {
            return b.n1 - a.n1;
        }
        // Secondary sort criterion: Fewer zeros first (ascending n0)
        return a.n0 - b.n0;
    });

    // 3. Calculate the total value modulo MOD
    let totalValue = 0n;
    let totalLength = 0;

    // Calculate total length first
    for (const frag of fragments) {
        totalLength += frag.length;
    }

    let L_remaining = BigInt(totalLength);

    for (const frag of fragments) {
        const n1 = BigInt(frag.n1);
        const n0 = BigInt(frag.n0);
        const length = frag.length;

        // L_suffix(p_k) is the length of all subsequent fragments
        L_remaining -= BigInt(length);

        // Calculate V_i = (2^n1 - 1) * 2^n0 mod MOD

        // P1 = 2^n1 mod MOD
        const P1 = power(2n, n1, MOD);

        // V1 = (2^n1 - 1) mod MOD
        // Add MOD before modulo to ensure positive result for subtraction
        const V1 = (P1 - 1n + MOD) % MOD; 

        // P0 = 2^n0 mod MOD
        const P0 = power(2n, n0, MOD);

        // V_i = V1 * P0 mod MOD
        const Vi = (V1 * P0) % MOD;

        // Term contribution = V_i * 2^L_remaining mod MOD
        const powerOf2 = power(2n, Number(L_remaining), MOD);
        const contribution = (Vi * powerOf2) % MOD;

        // Update total value
        totalValue = (totalValue + contribution) % MOD;
    }

    // Return the result as a standard Number, as it is guaranteed to be < 10^9 + 7
    return Number(totalValue);
}

